const DatePicker = ({ onConfirm, onCancel, init, last, isRange, appoitmentType}) => {
  const [initDate, set_initDate] = useState(init);
  const [lastDate, set_lastDate] = useState(last);
  const [isLastDate, set_isLastDate] = useState(false);
  const [showTimePicker, setShowTimePicker] = useState(false);
  const [appTimeSelected, setAppTimeSelected] = useState(null);

  
	
  const updDate = (dd) =>{
    if(appoitmentType){
      set_lastDate(null);
      set_isLastDate(true);
      set_initDate(dd);
      setShowTimePicker(true);
    }
    else if(isRange){
      if(isLastDate && dd>initDate){
        set_lastDate(dd);
        set_isLastDate(false)
      }else{
        set_initDate(dd);
        set_lastDate(null);
        set_isLastDate(true)
      }
    }else{
      set_initDate(dd);
      set_lastDate(null);
      set_isLastDate(true)
    }
  }

  const handleCancel = () =>{
    if(showTimePicker){
      setShowTimePicker(false);
    }else{
      onCancel()
    }
  }

  const handleOk = () =>{
    if(appoitmentType){
      setShowTimePicker(false);
      
      onConfirm(
        {initDate, appTimeSelected}
      );
    }else{
      (isRange && initDate && lastDate ||  initDate ) && 
      onConfirm(
        {initDate,lastDate}
      );
    }
    
  }

  return (
    <div className="dateBox darkmode" >
     
          <div className="date_header_box"  >
            <div  className={ "date_header_title"}>
                {isRange?"Select Ranges":"Escojer Dia"}
            </div>
          </div>
          <div className={"_dsplFlx date_calendar_header"} >
            <div  className={"date_range_title"}>
                {initDate? parseDateShort(initDate) :"Start Date"}
            </div>
            {isRange?
            <div  className={"date_range_space_title"}>
                {" - "}
            </div>:null}
             {isRange?
            <div  className={"date_range_title"}>
              {lastDate?parseDateShort(lastDate) :"End Date"}
            </div>
            :null}
            <div className="flexSpace"/>
            {/*
            <Icon2 name={"lead-pencil"} color={"var(--light-200)"}/>
            */}
          </div>
         { showTimePicker?
          <HorlyAppoitmentComponent
            onChange={setAppTimeSelected}
            date={initDate}
            selected={appTimeSelected}
            close={handleCancel}
          />
         :
        <CalendarComponent 
          onChangeDate={updDate}
          init={initDate}
          last={lastDate}
          isRange={isRange}
          appoitmentType={appoitmentType}
        />
        }
        <div className={"_dsplFlx calendar_action_group"} >
          <div className="flexSpace"/>
          <div
            onClick={handleCancel}
            size={40}
            className={"_dsplFlx"}
          >
            
              <div  className={ "btn_cal_cancel"}>
                {"Cancel"}
              </div>
          </div>
          <div
              onClick={handleOk}
          >
            <div
              className={"_dsplFlx"}
              style={{
                marginLeft: 16,
                marginRight: 8
              }}
            >
              <div  className={ "btn_cal_confirm"}>
              
                {"OK"}
              </div>
            </div>
          </div>
        </div>
    </div>
  )
  

}



export default CalendarPicker;






const CalendarComponent = ({ init, last ,onChangeDate, isRange, appoitmentType}) => {
  const [year, setYear] = useState((new Date()).getFullYear());
	const [month, setMonth] = useState((new Date()).getMonth());
	const [calendarData, setCalendarData] = useState([]);
  const [yearPicker, setYearPicker] = useState(false);
	const [obs, set_obs] = useState(1);
  

  useEffect(() => {
    let mdid = year+"_"+month;
    changeMonthAppoitments(mdid)
    setCalendarData(renderCalendar(month, year));
    setTimeout(() => {
      set_obs(gen16CodeId())
    }, 350);
    return () => {
      //
    }
  }, [month, year])

  let monthlabel = _monthNames["es"][month+1];





  const changeMonth = (m) =>{
    if(month+m > 11 || month+m < 0){
      let mm = month+m > 11 ? 0 :  month+m < 0 ? 11 : month+m;
      let yy = month+m > 11 ? year+1 : month+m < 0 ? year-1 : year;
      let mdid = yy+"_"+mm;
      //changeMonthAppoitments(mdid)
      setMonth(mm);
      setYear(yy);
    }
    else{
      
      //changeMonthAppoitments(mdid)
      setMonth(month+m);
    }
  }

  const changeYear = (yy) =>{
    setYear(yy);
    setYearPicker(false);
  }

  let hidePrevMtnBtn  = appoitmentType &&  year === (new Date()).getFullYear() && (month <= (new Date()).getMonth());

  const prevMonth = (m) =>{
    if(!hidePrevMtnBtn){
      changeMonth(-1);
      
    }
  }


  const onChange = (day) =>{
    const date = day && (new Date(year,month,day)).getTime();
    //date && onChangeDate(date+60000);
    date && onChangeDate(date);
  }

  


  return (
    <div style={{marginLeft: 4}}>
        <div  className={"_dsplFlx date_calendar_header"} >
            <div
              onClick={()=>setYearPicker(!yearPicker)}
              size={40}
            >
              <div
               className={"_dsplFlx"}
                style={{padding: 8}}
              >
                <div  className={ "date_calendar_header_yearmonth"}>
                  {monthlabel}
                </div>
                <div  className={ "date_calendar_header_yearmonth"}>
                  {year}
                </div>
                <div style={{paddingHorizontal:2}}>
                  <Icon2 name={'arrow_drop_down'} size={24} color={"var(--light-300)"} />
                </div>
              </div>
            </div>
          <div className="flexSpace"/>
          {!yearPicker && (
            <div  className={`_dsplFlx ${hidePrevMtnBtn?"disabled":""}`} >
              <div  style={{borderRadius:50}}>
                <div style={{padding:"0 2px", marginRight: 12}}  onClick={prevMonth}>
                  <Icon2 name={'arrow_left'} size={24} color={"var(--light-200)"} />
                </div>
              </div>
            </div>
            )
          }
           
          {!yearPicker?
           <div
            className={"_dsplFlx"}
            >
              <div  style={{borderRadius:50}}>
                <div style={{padding:"0 2px"}}  onClick={()=>changeMonth(1)}>
                  <Icon2 name={'arrow_right'} size={24} color={"var(--light-200)"} />
                </div>
              </div>
            </div>
          :null}
                    
          </div>
        {!yearPicker?
        <MonthRenderComponent 
          year={year}  
          month={month} 
          calendarData={calendarData} 
          onChange={onChange}
          init={init}
          last={last}
          range={isRange}
          appoitmentType={appoitmentType}
        />
        :
        <YearlistComponent year={year} onChange={changeYear}/> 
      }
    </div>
  )

}





const MonthRenderComponent = ({ year, month,  calendarData, onChange, init, last, range, appoitmentType}) => {

  let dayFactor = 86400000;

  let initSum =  Math.floor(init / dayFactor);
  let lastSum =  Math.floor(last / dayFactor);


  
  let todayTime = new Date((new Date()).getFullYear(),(new Date()).getMonth(),(new Date()).getDate());

  let apps_data = getStore("AppointmentsDates");

  return (
      <>
      <div  className={"_dsplFlx date_calendar_week_title"} >
      {_dayShortNames["en"].map((day, wwInd)=>{
        return (
          <div key={day + "_" +wwInd} className={"date_calendar_week_title_day"}>
            {day}
          </div>
        )
      })}
      </div>



      <div style={{minHeight: 282}}>
        {calendarData.map((week, wInd)=>{
          return(
            <div key={"week_"+ wInd} 
            className={"_dsplFlx"}>
                {week.map((dd, dIndx)=>{
                  let day = dd.day;

                  let dayTime = new Date(year,month,day);

                  let hiddePrev = appoitmentType &&  todayTime>dayTime;

                  
                  let daySum =  Math.floor(dayTime / dayFactor);

                  let isSelected = day && daySum > initSum && 
                  daySum < lastSum;

                  let firstValidDate = day && daySum === initSum;
                  let lastValidDate = day && daySum === lastSum;

                  let isToday = dd.isToday;



                  const youHasAppoitmentToday =()=>{
                    return numapps && ObjectKeys(numapps).filter(d=> numapps[d]?.userId === getStore(qryKprofile())?.userId )[0];
                  }

                  const handleChangeDay = (day) =>{
                    let openV = getStore(qryKprofile())?.isAdmin ||   aaps_lefts > 0 || youHasAppoitmentToday();
                    if(openV && !hiddePrev){
                      updStore("isTodayPickApp",isToday);
                      onChange(day);
                    }
                  }


                 

                  let dayKey = year+"_"+month+"_"+day;
                  
                  let numapps = apps_data?.[dayKey];

                  let aaps_tkd = numapps ? ObjectKeys(numapps)?.length : 0;
                  
                  let aaps_lefts =  day && !hiddePrev &&  howManyLeft(numapps, isToday)
                  
                  
                  return (
                    <div
                      key={dIndx + "_day_" + wInd}
                      className={`day_wrp ${!day?" empty_day":""} ${hiddePrev?" disable_day":""}${range?" range":""}${isToday?" isToday":""}${day && lastValidDate?" lastActiveDay":""}${day && firstValidDate?" firstActiveDay":""}${isSelected?" isSelected":""}`}
                    >
                    <div
                      className={`day_cal `}
                      onClick={()=>handleChangeDay(day)}
                    >
                      <div  
                       className={`day_num `}
                      >
                        {day}
                      </div>
                      <div  className={`apps_left`} >
                          {aaps_lefts?aaps_lefts:""}
                      </div>
                    </div>
                    </div>
                  )
                })}
            </div>
        )})}
      </div>
    </>
  )

}



const howManyLeft = ( numapps, isToday) => {
  let total = 0;

  if(numapps?.isDayOff){
    return total;
  }
  if(isToday){
    let today = (new Date());
    let chour = today.getHours();
    if(chour   >17){
      total =  null;
    }
    else if(chour > 9 && chour <   17){
      let recervedApp = 0;
      numapps &&  ObjectKeys(numapps).map(key=>{
        let hour = key.split("_")[1]*1;
        if(hour>chour){
          recervedApp += 1;
        }
      });
      total =  (17 - chour) - recervedApp
    }
    else{
      total =  9 -  (numapps ?ObjectKeys(numapps).length: 0)
    }
  }
  else{
    total = 9 -  (numapps ?ObjectKeys(numapps).length: 0)
  }
  return total;
}













const YearlistComponent = ({ year, onChange}) => {
  let yearList = Array.from({length: 9}, (_, i) => i + ((new Date()).getFullYear() - 0));

  let scrollRef = useRef();

  
  useEffect(() => {
    setTimeout(() => {
      let diff = (year - (new Date()).getFullYear()) / 3;
      let halfFactor = (16 + diff)* 41.6;
      scrollRef.current.scrollTo({ x: halfFactor, y: 0, animated: true })
    }, 20);
    return () => {
      //
    }
  }, [year])

  
  return (
        <div>
          <div

            ref={scrollRef}
            //contentInsetAdjustmentBehavior="automatic"
            style={{ maxHeight: "70vh"}}
            className={"scrollV"}
            >
            <div  
              className={"_dsplFlx year_wrp"}
            >
            {yearList.map(yy=>{
              return (
                <div
                  //onLayout={onLayout}
                  key={yy}
                  className={"year_tag"} 
                  onClick={()=>onChange(yy)}
                >
                  <div
                    className={`year-itm${yy===year?" activeYear":""} `}
                  >
                    <div  
                      className={`y_num`}
                    >
                      {yy}
                    </div>
                  </div>
                </div>
              )
            })}
            </div>
          </div>
        </div>
  )
}






















const HorlyAppoitmentComponent = ({ date, selected, onChange, close}) => {

  let dateC = new Date(date);
  let yy = dateC.getFullYear();
  let mm = dateC.getMonth();
  let dd = dateC.getDate();

  let today = (new Date());
  let chour = today.getHours();

  let isToday = getStore("isTodayPickApp");

 
  let hList = [9, 10,11,12,13,14,15,16,17]
  let hours = {
    9: "9:00-9:59 AM",
    10: "10:00-10:59 AM",
    11: "11:00-11:59 AM",
    12: "12:00-12:59 PM",
    13: "1:00-1:59 PM",
    14: "2:00-2:59 PM",
    15: "3:00-3:59 PM",
    16: "4:00-4:59 PM",
    17: "5:00-5:59 PM"
  }
  

  let scrollRef = useRef();

  
  let apps_data = getStore("AppointmentsDates");

  let dayKey = yy+"_"+mm+"_"+dd;
                  
  let numapps = apps_data?.[dayKey];

  let aaps_lefts =  howManyLeft(numapps, isToday)
                  


  const youHasAppoitmentToday =()=>{
    return numapps && ObjectKeys(numapps).filter(d=> numapps[d]?.userId === getStore(qryKprofile())?.userId )[0];
  }
  
  let appTd = youHasAppoitmentToday();

  const hasAppTitle =()=>{
    let hh = appTd?.split("_")[1]*1;
    let hour = hours?.[hh];
    let isValid = isToday ? chour < hh && hour : hour;
    return isValid && <div>Tiene una cita programada <span>({hour})</span> </div>;
  }

  const cancelAppoitment =(hrp)=>{
    deleteFsObj(yy+"_"+mm, dayKey, "app_"+hrp);
  }

  const OpenModalAlert =(t)=>{
    let hour = hours[appTd.split("_")[1]];
    let modal_data = {};
    modal_data["zIndex"] = 950;
    modal_data["height"] = "80vh";
    // data['observeResize']=true;
    modal_data["props"] = { minHeight: "1vh", overlay: true };
    modal_data["content"] = <AlertCancelAppoitment date={dateC} hour={hour} confirm={()=>cancelAppoitment(t)}/>
		
    OpenModal(modal_data);

  }
  

  const HandleDayChange =(t)=>{

    let yhas = youHasAppoitmentToday();

    let hasApp = numapps?.[yhas]?.userId === getStore(qryKprofile())?.userId; 

    let alreadyHave = hasApp && yhas.split("_")[1]*1 === t*1;

    if(alreadyHave){
      OpenModalAlert(t);
    }
    else{
      if(getStore(qryKprofile())?.isAdmin){
        onChange(t);
      }
      else if(hasApp){
          OpenToast({ text: "No puede hacer dos reservas el mismo dia", timeout: 1500 });
      }
      else{
        onChange(t);
      }
    }
    
  }
 
  const updDayOff =(v)=>{
    updFsObjByColl(yy+"_"+mm, dayKey, {"isDayOff":v });
    close();
  }


  return (
        <div  className={"hourlyPicker"}>
        {getStore(qryKprofile())?.isAdmin?
          <div className="_dsplFlx " style={{margin: "4px 7px 15px"}}>
             <div className="flexSpace"/>
            <CheckBoxSlide
              initvalue={numapps?.isDayOff}
              keyCode={77}
              updChange={(e)=>updDayOff(e)}
              color={"var(--primary-hover)"}
            />
            <span className={`checklabel`} style={{marginLeft: 6}}>
              {"Dia Off "}
            </span>
          </div>
          :null}
       
          {!getStore(qryKprofile())?.isAdmin && hasAppTitle() && (
            <div className={"title_appts_confirmed"}>
            {hasAppTitle()}
            </div>
          )}
            <div className={"_dsplFlx year_wrp"}  >
            {!numapps?.isDayOff && hList.map((hshift,inH)=>{

              let shit_id = "app_"+hshift;
              let hasTaken = numapps?.[shit_id];
              let alreadyHave = hasTaken?.userId === getStore(qryKprofile())?.userId;

              let y739 =  isToday && chour>hshift;

              let hs68Nu2 = hasTaken && !alreadyHave;




              if(y739 || hs68Nu2){
                return (
                  <div
                    key={hshift}
                    className={`year_tag ${hasTaken?"hasTaken":""}`} 
                  />
                )
              }
              else{
                return (
                  <div key={hshift}
                    className={`year_tag ${hasTaken?"hasTaken":""}${alreadyHave?" youAlreadyHave":""}`} 
                    onClick={()=>HandleDayChange(hshift, hasTaken)}
                  >
                    <div className={`year-itm${hshift===selected?" activeYear":""}`} >
                      <div   className={`y_num`} >
                        {hasTaken ? alreadyHave ? "reservado " : "-": hours[hshift]}
                      </div>
                    </div>
                  </div>
                )
              }
            })}
            </div>
        </div>
  )
}





