import { initializeApp } from 'firebase/app';
import { getFirestore, collection, getDocs, onSnapshot, doc , setDoc, deleteDoc , updateDoc, deleteField  } from 'firebase/firestore';
import { Base64Decode, updStore, callDispatchEvent } from './Utils';


function fs_cdata() {
    return '';
}

var fb_config = JSON.parse(Base64Decode(fs_cdata()));

var data_appointments = {}
var users_fs = {}



const app = initializeApp(fb_config);

const db = getFirestore(app);


let calendarMonthUnsubscribe = null;


  

export const changeMonthAppoitments = (yymonth)=>{
    calendarMonthUnsubscribe && calendarMonthUnsubscribe();
    snapshotMonthAppoitments(yymonth);
}



const snapshotMonthAppoitments = (yymonth)=>{
   
    const nameColl = collection(db, 'appointmentsV2' , yymonth, "days" );
    //console.log(nameColl)
    calendarMonthUnsubscribe = onSnapshot(nameColl, (snapshot) => {
      snapshot.docChanges().forEach((change) => {
        var _Id = change.doc.id;
        //console.log(change.doc)
      
        //compareDays(_Id)
        var s = change.doc.data();
        //console.log(_Id)
        // console.log(s)
        data_appointments[_Id] = s;
        updStore("AppointmentsDates",data_appointments);
        callDispatchEvent("fb_updated_1128h");
      });
    });
    return null;
}



export const updFsObjByColl = (mmK, ddK, obj)=>{
    const docRef = doc(db, 'appointmentsV2' , mmK, "days", ddK);
    setDoc(docRef,  obj , { merge: true });
  }



 

  export const deleteFsObj =  (mmK, ddK, fld) =>{
    const docRef = doc(db, 'appointmentsV2' , mmK, "days", ddK);
    updateDoc(docRef,{[fld]: deleteField()});
  }

